#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#define MAX 200005
char s[MAX];
char hidden[MAX * MAX];
int compare(const void *a, const void *b) {
    return strcmp(*(char **)a, *(char **)b);
}
int main() {
    int q, p, m, g = 0, k;
    scanf("%s", s);
    int len = strlen(s);
    char **subs = (char **)malloc(len * len * sizeof(char *));
    int idx = 0;
    for (int i = 0; i < len; i++) {
        for (int j = i + 1; j <= len; j++) {
            subs[idx] = (char *)malloc((j - i + 1) * sizeof(char));
            strncpy(subs[idx], s + i, j - i);
            subs[idx][j - i] = '\0';
            idx++;
        }
    }
    qsort(subs, idx, sizeof(char *), compare);
    int hid_idx = 0;
    for (int i = 0; i < idx; i++) {
        for (int j = 0; subs[i][j]; j++) {
            hidden[hid_idx++] = subs[i][j];
        }
    }
    scanf("%d", &q);
    while (q--) {
        scanf("%d %d", &p, &m);
        k = (p * g) % m + 1;
        printf("%c\n", hidden[k - 1]);
        g += hidden[k - 1];
    }
    return 0;
}

