#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
using namespace std;
int main() {
    string s;
    getline(cin, s);
    int q;
    cin >> q;
    cin.ignore();
    vector<string> subs;
    for (int i = 0; i < s.length(); i++) {
        for (int j = i + 1; j <= s.length(); j++) {
            subs.push_back(s.substr(i, j - i));
        }
    }
    sort(subs.begin(), subs.end());
    string hidden;
    for (auto &sub : subs) {
        hidden += sub;
    }
    int g = 0;
    while (q--) {
        int p, m;
        cin >> p >> m;
        int k = (p * g) % m + 1;
        cout << hidden[k - 1] << endl;
        g += hidden[k - 1];
    }
    return 0;
}

