import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String s = sc.nextLine();
        int q = sc.nextInt();
        sc.nextLine();
        String[] subs = new String[s.length() * s.length()];
        int idx = 0;
        for (int i = 0; i < s.length(); i++) {
            for (int j = i + 1; j <= s.length(); j++) {
                subs[idx++] = s.substring(i, j);
            }
        }
        Arrays.sort(subs);
        StringBuilder hidden = new StringBuilder();
        for (int i = 0; i < idx; i++) {
            hidden.append(subs[i]);
        }
        int g = 0;
        while (q-- > 0) {
            int p = sc.nextInt();
            int m = sc.nextInt();
            int k = (p * g) % m + 1;
            System.out.println(hidden.charAt(k - 1));
            g += hidden.charAt(k - 1);
        }
    }
}

